package com.example.single.console;

import com.example.single.core.*;
import com.example.single.engine.GameEngine;

import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class SingleConsoleMain {

    private static final int MAP_LEVEL_MAX = 5; // 최대 맵 레벨

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        GameEngine gameEngine = new GameEngine(); // GameEngine 인스턴스 생성
        SeedManager seedManager = new SeedManager(); // SeedManager 인스턴스 생성

        // --- 시뮬레이션 시작 ---
        System.out.println("===== 싱글 플레이 시뮬레이션 시작 =====");

        // 1. 시드 값 생성 (이전 하드코딩된 값 대신)
        long gameSeed = seedManager.generateNewSeed();
        System.out.println("🎲 게임 시드 생성: " + gameSeed);

        // 2. StageContentGenerator 를 이용한 맵 생성
        StageContentGenerator stageContentGenerator = new StageContentGenerator(gameSeed);
        List<StageContent> map = new ArrayList<>();

        // StageContentGenerator 에서 맵 정보 생성 (MAP_LEVEL_MAX 층 만큼)
        for (int i = 0; i < MAP_LEVEL_MAX; i++) {
            StageContent stageContent = stageContentGenerator.generateStageContent(i);
            map.add(stageContent);
        }

        // 3. 생성된 맵 정보 콘솔에 출력
        System.out.println("\n🗺️ 생성된 맵 정보:");
        for (int i = 0; i < map.size(); i++) {
            StageContent stageContent = map.get(i);
            String stageName = stageContent.stageName;
            String stageType = stageContent.stageType.name(); // Enum을 문자열로 변환
            String eventName = stageContent.eventDefinition.eventName;
            String eventDesc = stageContent.eventDefinition.desc; // <-- 'description' 대신 'desc' 사용
            EventGrade eventGrade = stageContent.eventDefinition.grade;

            System.out.printf("  [Level %d] %s (%s) - 이벤트: %s (등급: %s, 설명: %s)\n",
                    i, stageName, stageType, eventName, eventGrade.name(), eventDesc);
        }

        System.out.println("\n--- 게임 진행 시뮬레이션 ---");

        // 게임 엔진을 사용하여 맵 기반으로 게임 진행 (예시)
        // TODO: 실제 게임 로직 구현 (Player, Monster, Item 등)
        // 현재는 맵 정보를 기반으로 단순히 각 스테이지를 순회하는 것으로 대체
        int currentLevel = 0;
        while (currentLevel < map.size()) {
            StageContent currentStage = map.get(currentLevel);
            System.out.printf("\n>>> Level %d: %s (%s) 진입 <<<\n", currentLevel, currentStage.stageName, currentStage.stageType.name());

            // --- 스테이지별 이벤트 처리 (예시) ---
            // 이 부분은 실제 게임 로직에 따라 크게 달라집니다.
            // 여기서는 eventDefinition을 이용해 간단한 시뮬레이션을 보여줍니다.

            EventDefinition eventDef = currentStage.eventDefinition;
            System.out.println("  발생 이벤트: " + eventDef.eventName);
            System.out.println("  이벤트 등급: " + eventDef.grade);
            System.out.println("  이벤트 설명: " + eventDef.desc);

            // TODO: 실제 이벤트 처리 로직 구현 (예: 플레이어 HP 회복, 카드 획득 등)
            // 예를 들어, 이벤트 등급에 따라 다른 효과를 적용할 수 있습니다.
            switch (eventDef.grade) {
                case NORMAL:
                    System.out.println("  효과: 일반적인 이벤트입니다.");
                    break;
                case RARE:
                    System.out.println("  효과: 약간 특별한 이벤트입니다!");
                    // 예: Player HP 회복
                    // gameEngine.getPlayer().heal(10);
