```java
package com.example.single.core;

import java.util.ArrayList;
import java.util.List;
import java.util.Random;

import static com.example.single.core.EventGrade.EPIC;
import static com.example.single.core.EventGrade.LEGENDARY;
import static com.example.single.core.EventGrade.MYTHIC;
import static com.example.single.core.EventGrade.RARE;

/**
 * 스테이지 콘텐츠를 생성하는 클래스.
 * 각 스테이지(층)마다 랜덤하게 맵, 적, 이벤트 등을 결정한다.
 */
public class StageContentGenerator {

    private final Random random;
    private final EventDataLoader eventDataLoader;
    private final CardDataLoader cardDataLoader;

    public StageContentGenerator(EventDataLoader eventDataLoader, CardDataLoader cardDataLoader) {
        this.random = new Random();
        this.eventDataLoader = eventDataLoader;
        this.cardDataLoader = cardDataLoader;
    }

    /**
     * 특정 게임 시드값을 기반으로 스테이지 콘텐츠를 생성합니다.
     *
     * @param gameSeed 맵 생성을 위한 시드값
     * @return 생성된 스테이지 콘텐츠 목록
     */
    public List<StageContent> generateStageContents(long gameSeed) {
        // 이전 상태 초기화 (게임 엔진의 새로운 인스턴스 생성 시, 혹은 스테이지 전환 시)
        this.random.setSeed(gameSeed);

        List<StageContent> stageContents = new ArrayList<>();
        // 총 층수 (예시)
        int totalFloors = 5;

        for (int i = 1; i <= totalFloors; i++) {
            String stageType = determineStageType(i);
            StageContent stageContent;

            if ("BATTLE".equals(stageType)) {
                // 전투 스테이지 생성 로직 (이후 구현)
                stageContent = createBattleStage(i);
            } else if ("EVENT".equals(stageType)) {
                // 이벤트 스테이지 생성 로직
                stageContent = createEventStage(i);
            } else if ("SHOP".equals(stageType)) {
                // 상점 스테이지 생성 로직 (이후 구현)
                stageContent = createShopStage(i);
            } else {
                // 기본값 또는 예외 처리
                stageContent = createDefaultStage(i);
            }
            stageContents.add(stageContent);
        }
        return stageContents;
    }

    /**
     * 현재 층에 따라 스테이지 타입을 결정합니다.
     * (예: 전투, 이벤트, 상점 등)
     * @param floor 현재 층 번호
     * @return 결정된 스테이지 타입 문자열
     */
    private String determineStageType(int floor) {
        // 단순 랜덤 결정 (이후 층 번호, 게임 진행 상황에 따라 복잡하게 변경 가능)
        // 현재는 전투, 이벤트, 상점을 3:2:1 비율로 결정
        int randInt = random.nextInt(6); // 0 ~ 5
        if (randInt < 3) {
            return "BATTLE";
        } else if (randInt < 5) {
            return "EVENT";
        } else {
            return "SHOP";
        }
    }

    /**
     * 전투 스테이지 콘텐츠를 생성합니다.
