        EventDefinition randomEvent = selectRandomEvent();
        // 현재는 임의의 카드 1장을 선택하여 이벤트에 포함시킵니다.
        // TODO: 이벤트 종류에 따라 필요한 카드나 아이템을 동적으로 결정해야 합니다.
        CardInstance randomCard = cardDataLoader.getRandomCardInstance(random.nextLong());
