     * @return 랜덤하게 선택된 EventDefinition 객체
     */
    private EventDefinition selectRandomEvent() {
        List<EventDefinition> events = eventDataLoader.getEvents();
        if (events.isEmpty()) {
            // 이벤트가 없을 경우 기본 이벤트 반환 또는 예외 처리
            return new EventDefinition("default_event", "기본 이벤트", "설명이 없습니다.", "default_event_key");
        }
        // 이벤트 등급에 따라 가중치를 부여하여 선택할 수도 있습니다.
        // 우선은 단순 랜덤 선택
        int eventIndex = random.nextInt(events.size());
        EventDefinition selectedEvent = events.get(eventIndex);

        // 이벤트 등급(EventGrade)에 따라 추가적인 효과를 적용할 수 있습니다.
        // 예를 들어, 희귀 등급 이상일 때 플레이어에게 더 큰 이득을 줄 수 있습니다.
        // 현재는 EventDefinition 자체에 등급이 포함되어 있지 않아,
        // selectRandomEvent 메서드 내에서 등급을 기반으로 선택 로직을 추가할 수 있습니다.

        return selectedEvent;
    }
}
